当然可以！快速排序有很多优化空间，我来给你几个常见的优化版本：

## 优化1：三数取中法（解决最坏情况）

最坏情况发生在数组已经有序时，选最右边作为基准会导致 O(n²)。三数取中法可以避免这个问题。

```java
public class QuickSortOptimized1 {

    public static void quickSort(int[] arr) {
        if (arr == null || arr.length == 0) return;
        quickSort(arr, 0, arr.length - 1);
    }

    private static void quickSort(int[] arr, int left, int right) {
        if (left >= right) return;

        // 优化：三数取中法选择基准，避免最坏情况
        int pivotIndex = medianOfThree(arr, left, right);
        // 将基准交换到最右边，复用之前的 partition 逻辑
        swap(arr, pivotIndex, right);

        int pivotPos = partition(arr, left, right);
        quickSort(arr, left, pivotPos - 1);
        quickSort(arr, pivotPos + 1, right);
    }

    // 三数取中：取 left、mid、right 三个位置的中间值
    private static int medianOfThree(int[] arr, int left, int right) {
        int mid = left + (right - left) / 2;
        // 简单的排序：让 arr[left] <= arr[mid] <= arr[right]
        if (arr[left] > arr[mid]) swap(arr, left, mid);
        if (arr[left] > arr[right]) swap(arr, left, right);
        if (arr[mid] > arr[right]) swap(arr, mid, right);
        return mid; // mid 就是中间值
    }

    private static int partition(int[] arr, int left, int right) {
        int pivot = arr[right];
        int i = left;
        for (int j = left; j < right; j++) {
            if (arr[j] < pivot) {
                swap(arr, i, j);
                i++;
            }
        }
        swap(arr, i, right);
        return i;
    }

    private static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
```

## 优化2：插入排序 + 小数组优化（减少递归深度）

当子数组足够小时（比如 ≤ 16），改用插入排序，因为对小数组来说插入排序比快速排序更快。

```java
public class QuickSortOptimized2 {

    private static final int INSERTION_THRESHOLD = 16;

    public static void quickSort(int[] arr) {
        if (arr == null || arr.length == 0) return;
        quickSort(arr, 0, arr.length - 1);
    }

    private static void quickSort(int[] arr, int left, int right) {
        // 优化：小数组改用插入排序
        if (right - left + 1 <= INSERTION_THRESHOLD) {
            insertionSort(arr, left, right);
            return;
        }

        int pivotIndex = medianOfThree(arr, left, right);
        swap(arr, pivotIndex, right);
        int pivotPos = partition(arr, left, right);
        quickSort(arr, left, pivotPos - 1);
        quickSort(arr, pivotPos + 1, right);
    }

    // 插入排序（只排序指定区间）
    private static void insertionSort(int[] arr, int left, int right) {
        for (int i = left + 1; i <= right; i++) {
            int key = arr[i];
            int j = i - 1;
            while (j >= left && arr[j] > key) {
                arr[j + 1] = arr[j];
                j--;
            }
            arr[j + 1] = key;
        }
    }

    private static int medianOfThree(int[] arr, int left, int right) {
        int mid = left + (right - left) / 2;
        if (arr[left] > arr[mid]) swap(arr, left, mid);
        if (arr[left] > arr[right]) swap(arr, left, right);
        if (arr[mid] > arr[right]) swap(arr, mid, right);
        return mid;
    }

    private static int partition(int[] arr, int left, int right) {
        int pivot = arr[right];
        int i = left;
        for (int j = left; j < right; j++) {
            if (arr[j] < pivot) {
                swap(arr, i, j);
                i++;
            }
        }
        swap(arr, i, right);
        return i;
    }

    private static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
```

## 优化3：双路快排（处理大量重复元素）

当数组中有大量重复元素时，普通快排会退化。双路快排把等于 pivot 的元素均匀分到两边。

```java
public class QuickSortOptimized3 {

    public static void quickSort(int[] arr) {
        if (arr == null || arr.length == 0) return;
        quickSort(arr, 0, arr.length - 1);
    }

    private static void quickSort(int[] arr, int left, int right) {
        if (left >= right) return;

        // 双路快排分区
        int[] range = partition(arr, left, right);
        quickSort(arr, left, range[0] - 1);
        quickSort(arr, range[1] + 1, right);
    }

    // 双路快排：返回等于 pivot 的区间 [lt, gt]
    private static int[] partition(int[] arr, int left, int right) {
        // 随机选基准，避免最坏情况
        int randomIdx = left + (int)(Math.random() * (right - left + 1));
        swap(arr, left, randomIdx);
        int pivot = arr[left];

        int lt = left;     // arr[left+1...lt] < pivot
        int gt = right;    // arr[gt...right] > pivot
        int i = left + 1;  // arr[lt+1...i-1] == pivot

        while (i <= gt) {
            if (arr[i] < pivot) {
                swap(arr, i, lt);
                lt++;
                i++;
            } else if (arr[i] > pivot) {
                swap(arr, i, gt);
                gt--;
            } else {
                i++;
            }
        }
        // 返回等于 pivot 的区间
        return new int[]{lt, gt};
    }

    private static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
```

## 优化4：最终版（结合所有优化）

```java
public class QuickSortUltimate {

    private static final int INSERTION_THRESHOLD = 16;

    public static void quickSort(int[] arr) {
        if (arr == null || arr.length == 0) return;
        quickSort(arr, 0, arr.length - 1);
    }

    private static void quickSort(int[] arr, int left, int right) {
        // 优化1：小数组用插入排序
        if (right - left + 1 <= INSERTION_THRESHOLD) {
            insertionSort(arr, left, right);
            return;
        }

        // 优化2：三数取中 + 双路快排
        int[] range = partition(arr, left, right);
        quickSort(arr, left, range[0] - 1);
        quickSort(arr, range[1] + 1, right);
    }

    private static int[] partition(int[] arr, int left, int right) {
        // 三数取中
        int mid = left + (right - left) / 2;
        if (arr[left] > arr[mid]) swap(arr, left, mid);
        if (arr[left] > arr[right]) swap(arr, left, right);
        if (arr[mid] > arr[right]) swap(arr, mid, right);
        // 将中间值作为基准放到 left 位置
        swap(arr, left, mid);
        int pivot = arr[left];

        int lt = left;
        int gt = right;
        int i = left + 1;

        while (i <= gt) {
            if (arr[i] < pivot) {
                swap(arr, i, lt);
                lt++;
                i++;
            } else if (arr[i] > pivot) {
                swap(arr, i, gt);
                gt--;
            } else {
                i++;
            }
        }
        return new int[]{lt, gt};
    }

    private static void insertionSort(int[] arr, int left, int right) {
        for (int i = left + 1; i <= right; i++) {
            int key = arr[i];
            int j = i - 1;
            while (j >= left && arr[j] > key) {
                arr[j + 1] = arr[j];
                j--;
            }
            arr[j + 1] = key;
        }
    }

    private static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
```

